CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TABLE IF NOT EXISTS agents(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),user_id UUID NOT NULL UNIQUE,code VARCHAR(20) UNIQUE,status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE',float_balance DECIMAL(18,2) NOT NULL DEFAULT 0,00,commission_rate DESIMMAL(5,4) NOT NULL DEFAULT 0.0030,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS agent_transactions(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),reference VARCHAR(30) UNIQUE,agent_id UUID REFERENCES agents(id),type VARCHAR(20) NOT NULL,amount DECIMAL(18,2),NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'PENDING_AGENT',created_at TIMESTAMPT@ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS agent_commissions(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),agent_id UUID,commission_amount DECIMAL(18,2),NOT NULL,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
